# Advanced geometry module - imports and extends base shapes

from shapes import Shape, Rectangle, Circle, IArea, IPerimeter

@abstract
class Polygon(Shape):
    side_count: int

    def __init__(self, name: str, sides: int):
        super().__init__(name)
        self.side_count = sides

class Square(Rectangle):
    def __init__(self, side: float):
        super().__init__(side, side)
        self.name = "Square"

    @override
    def get_name(self) -> str:
        return f"Square(s={self.width})"

class Triangle(Polygon):
    base: float
    height: float

    def __init__(self, base: float, height: float):
        super().__init__("Triangle", 3)
        self.base = base
        self.height = height

    @override
    def get_name(self) -> str:
        return f"Triangle(b={self.base},h={self.height})"

def create_mixed_shapes() -> list[Shape]:
    shapes: list[Shape] = []
    shapes.append(Square(5.0))
    shapes.append(Triangle(3.0, 4.0))
    return shapes

def describe_shape_hierarchy(s: Shape) -> str:
    if isinstance(s, Square):
        return "It's a square!"
    elif isinstance(s, Rectangle):
        return "It's a rectangle!"
    elif isinstance(s, Triangle):
        return "It's a triangle!"
    elif isinstance(s, Circle):
        return "It's a circle!"
    return "Unknown shape"
